import vex
from langgraph.checkpoint.memory import MemorySaver

class HiringGraph:
    def __init__(self):
        self.checkpointer = MemorySaver()
        vex.watch(self.checkpointer, 'cycle-limit=5')

    @vex.verify(guards=['no-infinite-cycles'])
    def invoke_with_safeguards(self, input):
        config = {'configurable': {'thread_id': input['candidate_id']}}

        # Vex circuit breaker prevents bias amplification loops
        result = self.graph.invoke(input, config)

        # Final EEOC compliance check
        if result['score'] > 0.9 and len(result['re_rank_iterations']) > 3:
            vex.alert('potential-bias-amplification')

        return result

hr_graph = HiringGraph()
